# mkfifo fifo
# cat readfifo.select.c

#include <fcntl.h>
#include <err.h>
#include <errno.h>
#include <sys/types.h>
#include <sys/time.h>
#include <unistd.h>
#include <stdio.h>
#include <string.h>

int
main(int argc,char **argv)
{
	int fd;
	char *fn="fifo";

	if(argc>1)
		fn=*(argv+1);


	if((fd=open(fn,O_RDONLY|O_NONBLOCK))<0)
		err(errno,"can't open %s",fn);

	for(;;){
		fd_set fds;
		int r;
		struct timeval tv;
		size_t sz;
		char b[64];

		tv.tv_sec=5;
		tv.tv_usec=0;
		FD_ZERO(&fds);
		FD_SET(fd,&fds);
		r=select(FD_SETSIZE,&fds,NULL,NULL,&tv);
		if(r<0)
			err(errno,"select return %d ",r);
		if(r==0){
			fputs("timeout\n",stderr);
			continue;
		}
		sz=read(fd,b,63);
		if(sz<0)
			err(errno,"read fifo return %d",sz);
		if(!sz){
			fputs("read null bites\n",stderr);
			continue;
		}
		b[sz]='\0';
		puts(b);
		fflush(stdout);
	}
}

