#include <sys/uio.h>
#include <unistd.h>
#include <poll.h>
#include <stdio.h>

int
main(int argc,char **argv)
{
     int fd;
     char *fn="fifo";

     if(argc>1)
	  fn=*(argv+1);

     fd=open(fn,O_RDONLY|O_NONBLOCK);
     if(fd<0)
	  err(errno,"cannot open %s",fn);

     for(;;){
	  struct pollfd pfd;
	  int pr;
	  size_t sz;
	  char b[64];

	  pfd.fd=fd;
	  /*pfd.events=POLLRDNORM;*/
	  pfd.events=POLLIN;
	  pr=poll(&pfd,1,5000);
	  if(pr==-1)
	       err(errno,"error in poll");
	  if(!pr){
	       fputs("timeout\n",stderr);
	       continue;
	  }
	  puts("reading");fflush(stdout);
	  sz=read(fd,b,63);
	  if(sz<0)
	       err(errno,"cannot read");
	  if(!sz){
	       fputs("read null bytes\n",stderr);
	       continue;
	  }
	  b[sz]='\0';
	  puts(b);
	  fflush(stdout);
     }
}

